67	export function categorizeDevice(type: string): DeviceCategory {
68	  if (type.includes('dimmer') || type.includes('colorController')) return 'dimmer';
69	  if (type.includes('Switch')) return 'light';
70	  if (type.includes('hvacSystem')) return 'thermostat';
71	  if (type.includes('smokeDetector') || type.includes('coDetector') || type.includes('floodSensor')) return 'safety';
72	  if (type.includes('electricMeter')) return 'energy';
73	  if (type.includes('Sensor') || type.includes('Detector')) return 'sensor';
